documents.style:
/* Alignment */
      .sk-docs-rendered mtable.right-align mtd,
      .sk-docs-rendered mtable mtd.right-align,
      .sk-docs-rendered mtable.left-align mtd.right-align,
      .sk-docs-rendered mtable.aligned mtd:nth-child(odd) {
        justify-items: end;
        text-align: right;
      }
      .sk-docs-rendered mtable.cases mtd,
      .sk-docs-rendered mtable.left-align mtd,
      .sk-docs-rendered mtable mtd.left-align,
      .sk-docs-rendered mtable.aligned mtd:nth-child(even),
      .sk-docs-rendered math:is(:not([display])) > mtable.multiline-equation mtd {
        justify-items: start;
        text-align: left;
      }
      .sk-docs-rendered mtable.cases mtd,
      .sk-docs-rendered mtable.aligned mtd,
      .sk-docs-rendered mtable mtd.flushed,
      .sk-docs-rendered mtable mtd.left-flush {
        padding-left: 0;
      }
      .sk-docs-rendered mtable.cases mtd,
      .sk-docs-rendered mtable.aligned mtd,
      .sk-docs-rendered mtable mtd.flushed,
      .sk-docs-rendered mtable mtd.right-flush {
        padding-right: 0;
      }

      /* Tables */
      .sk-docs-rendered mtable {
        math-style: inherit;
      }
      .sk-docs-rendered mtd {
        math-depth: auto-add;
        math-style: compact;
        math-shift: compact;
      }

      /* Equations */
      .sk-docs-rendered mtable.multiline-equation mtd {
        math-depth: inherit;
        math-style: inherit;
        math-shift: inherit;
        padding: 0;
      }
      .sk-docs-rendered math > mtable.multiline-equation mtr:not(:last-child) mtd {
        padding-bottom: 0.5em;
      }

      /* Fractions */
      .sk-docs-rendered mfrac {
        padding-inline: 0;
        margin-inline: 0.1em;
      }

      /* Accents */
      .sk-docs-rendered mover[accent="true" i] > :first-child {
        font-feature-settings: "dtls";
      }
      .sk-docs-rendered mover.dotted[accent="true" i] > :first-child {
        font-feature-settings: "dtls" 0;
      }

      /* Other rules for scriptlevel, displaystyle and math-shift */
      .sk-docs-rendered munder > :nth-child(2),
      .sk-docs-rendered munderover > :nth-child(2) {
        math-shift: compact
      }
      .sk-docs-rendered munder[accentunder="true" i] > :not(:first-child),
      .sk-docs-rendered mover[accent="true" i] > :not(:first-child) {
        math-depth: inherit;
        math-style: inherit;
        math-shift: inherit;
      }

